css:
.print-format {
    font-family: Arial, sans-serif;
    padding: 20px;
}
.header {
    text-align: center;
    border-bottom: 2px solid #333;
    padding-bottom: 15px;
    margin-bottom: 20px;
}
.header h1 {
    margin: 0;
    font-size: 24px;
    color: #333;
}
.header h2 {
    margin: 5px 0 0;
    font-size: 18px;
    color: #666;
    font-weight: normal;
}
.info-section {
    margin-bottom: 20px;
}
.info-section table {
    width: 100%;
}
.info-section td {
    padding: 4px 8px;
    vertical-align: top;
}
.info-label {
    font-weight: bold;
    width: 150px;
    color: #555;
}
.items-table {
    width: 100%;
    border-collapse: collapse;
    margin: 15px 0;
}
.items-table th {
    background-color: #f5f5f5;
    border: 1px solid #ddd;
    padding: 10px;
    text-align: left;
    font-weight: bold;
}
.items-table td {
    border: 1px solid #ddd;
    padding: 8px 10px;
}
.items-table .text-right {
    text-align: right;
}
.totals-section {
    margin-top: 20px;
    float: right;
    width: 350px;
}
.totals-section table {
    width: 100%;
}
.totals-section td {
    padding: 6px 10px;
}
.totals-section .total-label {
    font-weight: bold;
    text-align: right;
}
.totals-section .total-value {
    text-align: right;
    width: 150px;
}
.grand-total {
    font-size: 16px;
    font-weight: bold;
    border-top: 2px solid #333;
}
